label("$P$",(7.0711,7.0711),N);
label("$Q$",(7.0711,-7.0711),S);
label("$R$",(0,0),W);
label("2",(7.0711,7.0711)--(7.0711,-7.0711),E);
label("$45^\circ$",(7.0711,-4.0711),W);
label("$45^\circ$",(7.0711,4.0711),W);
